const ev = $input.first().json;

// Parse start time — handle both dateTime and all-day (date only)
const startRaw = ev.start?.dateTime || ev.start?.date || '';
const endRaw   = ev.end?.dateTime   || ev.end?.date   || '';

const startDate = new Date(startRaw);
const endDate   = new Date(endRaw);
const now       = new Date();

const msUntil = startDate.getTime() - now.getTime();
const hoursUntil = msUntil / (1000 * 60 * 60);
const daysUntil  = Math.floor(hoursUntil / 24);

// Format readable date
const dateOptions = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
const timeOptions = { hour: '2-digit', minute: '2-digit', timeZoneName: 'short' };
const eventDateStr = startDate.toLocaleDateString('en-US', dateOptions);
const eventTimeStr = startDate.toLocaleTimeString('en-US', timeOptions);

const title    = ev.summary || 'Upcoming Event';
const desc     = (ev.description || '').replace(/<[^>]+>/g, '').trim().substring(0, 400);
const location = ev.location || 'Online / TBD';
const eventId  = ev.id || ev.iCalUID || `evt-${Date.now()}`;
const organizer = ev.organizer?.displayName || ev.organizer?.email || 'Organizer';
const eventUrl  = ev.htmlLink || '';

return [{
  json: {
    eventId,
    title,
    description: desc,
    location,
    organizer,
    eventUrl,
    startRaw,
    endRaw,
    eventDateStr,
    eventTimeStr,
    hoursUntil: Math.round(hoursUntil),
    daysUntil
  }
}];

const eventData = $('Code — Parse & Enrich Event Data').item.json;
const uploadResp = $('UploadToURL — Host Promo Graphic').item.json;
const startRaw   = eventData.startRaw;

const hostedImageUrl =
  uploadResp?.url ??
  uploadResp?.data?.url ??
  uploadResp?.file?.url ??
  uploadResp?.link ??
  'https://placeholder.com/event-graphic.jpg';

const startMs = new Date(startRaw).getTime();

// Build 3 schedule slots
const slots = [
  {
    slotIndex: 1,
    label: '48 Hours Before',
    urgency: 'early',
    scheduledAt: new Date(startMs - 48 * 60 * 60 * 1000).toISOString()
  },
  {
    slotIndex: 2,
    label: '24 Hours Before',
    urgency: 'reminder',
    scheduledAt: new Date(startMs - 24 * 60 * 60 * 1000).toISOString()
  },
  {
    slotIndex: 3,
    label: '1 Hour Before',
    urgency: 'last_call',
    scheduledAt: new Date(startMs - 1 * 60 * 60 * 1000).toISOString()
  }
];

// Return one item per schedule slot
return slots.map(slot => ({
  json: {
    ...eventData,
    hostedImageUrl,
    slotIndex:   slot.slotIndex,
    slotLabel:   slot.label,
    urgency:     slot.urgency,
    scheduledAt: slot.scheduledAt
  }
}));

const aiResp   = $input.first().json;
const slotData = $('Wait — Until Scheduled Post Time').item.json;

let captions = {};
try {
  const raw     = aiResp?.choices?.[0]?.message?.content || '{}';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  captions      = JSON.parse(cleaned);
} catch(e) {
  const fallback = `🎉 ${slotData.title} — ${slotData.eventDateStr} at ${slotData.location}. Don't miss it! ${slotData.eventUrl}`;
  captions = {
    linkedin: fallback + ' #Event #MustAttend',
    twitter:  `📅 ${slotData.title} — ${slotData.eventDateStr} ${slotData.eventUrl} #Event`,
    facebook: fallback + ' #Community #Event'
  };
}

return [{
  json: {
    ...slotData,
    linkedinCaption: captions.linkedin  || '',
    twitterCaption:  captions.twitter   || '',
    facebookCaption: captions.facebook  || '',
    postedAt: new Date().toISOString()
  }
}];

